import{_ as a,a as e,b as d,c as o}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as i,o as r,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Добавление канала WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/webdav.md","filePath":"ru-RU/upload/webdav.md","lastUpdated":1781962217000}'),l={name:"ru-RU/upload/webdav.md"};function p(c,t,h,b,u,m){return r(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="добавление-канала-webdav" tabindex="-1">Добавление канала WebDAV <a class="header-anchor" href="#добавление-канала-webdav" aria-label="Permalink to &quot;Добавление канала WebDAV&quot;">​</a></h1><h2 id="когда-это-лучшии-вариант" tabindex="-1">Когда это лучший вариант <a class="header-anchor" href="#когда-это-лучшии-вариант" aria-label="Permalink to &quot;Когда это лучший вариант&quot;">​</a></h2><p>Используйте канал WebDAV, если:</p><ul><li>у вас есть NAS, облачный диск или объектное хранилище с WebDAV endpoint;</li><li>хотите хранить загруженные изображения в собственной WebDAV-директории;</li><li>хотите сохранять учетные данные в таблице D1 <code>upload_channels</code>, а не держать их надолго открытыми на фронтенде.</li></ul><h2 id="что-подготовить-заранее" tabindex="-1">Что подготовить заранее <a class="header-anchor" href="#что-подготовить-заранее" aria-label="Permalink to &quot;Что подготовить заранее&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Серверный WebDAV URL, например <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>Имя пользователя для входа в WebDAV-сервис.</td></tr><tr><td>Password</td><td>Пароль для входа в WebDAV-сервис.</td></tr><tr><td>Authentication mode</td><td>По умолчанию <code>Basic</code>. Используйте <code>Digest</code> или автоматическое согласование только если это требует сервер.</td></tr><tr><td>Storage directory</td><td>Директория для хранения файлов. По умолчанию <code>imgbed</code>.</td></tr></tbody></table><h2 id="где-добавить-канал" tabindex="-1">Где добавить канал <a class="header-anchor" href="#где-добавить-канал" aria-label="Permalink to &quot;Где добавить канал&quot;">​</a></h2><ol><li>Откройте системные настройки.</li><li>Перейдите в настройки загрузки.</li><li>Нажмите Add Channel в правом верхнем углу.</li><li>Выберите <code>WebDAV</code>.</li></ol><h2 id="поля-настроики" tabindex="-1">Поля настройки <a class="header-anchor" href="#поля-настроики" aria-label="Permalink to &quot;Поля настройки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Что означает</th><th>Обязательно</th></tr></thead><tbody><tr><td>Название канала</td><td>Понятное имя WebDAV-канала, например <code>koofr</code> или <code>nas</code>.</td><td>Да</td></tr><tr><td>Endpoint</td><td>Полный WebDAV endpoint, включая <code>https://</code>.</td><td>Да</td></tr><tr><td>Username</td><td>Имя пользователя WebDAV.</td><td>Да</td></tr><tr><td>Password</td><td>Пароль WebDAV.</td><td>Да</td></tr><tr><td>Authentication mode</td><td>Обычно <code>Basic</code>; используйте <code>Digest</code>, если сервер требует digest authentication.</td><td>Да</td></tr><tr><td>Storage directory</td><td>Директория, где хранятся файлы. По умолчанию <code>imgbed</code>.</td><td>Нет</td></tr></tbody></table><h2 id="пример-fie-nl-tab-digital" tabindex="-1">Пример: fie.nl.tab.digital <a class="header-anchor" href="#пример-fie-nl-tab-digital" aria-label="Permalink to &quot;Пример: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-создаите-app-password" tabindex="-1">1. Создайте app password <a class="header-anchor" href="#_1-создаите-app-password" aria-label="Permalink to &quot;1. Создайте app password&quot;">​</a></h3><p>Откройте настройки безопасности аккаунта, найдите application passwords и создайте новый app password.</p><p><img src="'+a+'" alt="Создание app password" loading="lazy"></p><p>После создания скопируйте и сохраните новый app password. Обычно он показывается только один раз.</p><p><img src="'+e+'" alt="Сохранение нового app password" loading="lazy"></p><h3 id="_2-заполните-webdav-конфигурацию-в-imgbed" tabindex="-1">2. Заполните WebDAV-конфигурацию в ImgBed <a class="header-anchor" href="#_2-заполните-webdav-конфигурацию-в-imgbed" aria-label="Permalink to &quot;2. Заполните WebDAV-конфигурацию в ImgBed&quot;">​</a></h3><p>Вернитесь в ImgBed и добавьте WebDAV-канал:</p><table tabindex="0"><thead><tr><th>Поле в интерфейсе</th><th>Значение</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV URL, предоставленный <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Username</td><td>Ваш WebDAV username.</td></tr><tr><td>Password</td><td>App password, который вы только что создали.</td></tr><tr><td>Authentication mode</td><td>В большинстве случаев начните с <code>Basic</code>.</td></tr><tr><td>Storage directory</td><td>По умолчанию <code>imgbed</code>; при необходимости можно указать свою директорию.</td></tr></tbody></table><p><img src="'+d+'" alt="Заполнение конфигурации" loading="lazy"></p><h2 id="поведение-при-загрузке-больших-фаилов" tabindex="-1">Поведение при загрузке больших файлов <a class="header-anchor" href="#поведение-при-загрузке-больших-фаилов" aria-label="Permalink to &quot;Поведение при загрузке больших файлов&quot;">​</a></h2><p>Канал WebDAV использует настоящее session-based chunked upload.</p><p>Небольшие файлы загружаются как один цельный файл. Файлы больше 64 MiB автоматически делятся на части примерно по 10 MiB и загружаются в удаленную директорию чанков.</p><p>WebDAV-сервису не нужно поддерживать <code>partial update</code> или запись по offset. ImgBed не склеивает чанки в один большой файл на удаленном сервере. Вместо этого он хранит manifest чанков и читает их по порядку, когда файл запрашивают.</p><p>На практике:</p><table tabindex="0"><thead><tr><th>Размер файла</th><th>Способ загрузки</th><th>Структура в удаленном хранилище</th></tr></thead><tbody><tr><td>64 MiB или меньше</td><td>Обычная загрузка</td><td>Один цельный файл</td></tr><tr><td>Больше 64 MiB</td><td>Настоящее session chunked upload</td><td>Директория чанков с несколькими файлами-частями</td></tr></tbody></table><p>Директория чанков влияет только на структуру удаленного хранилища. Она не меняет URL файла в ImgBed. Пользователи по-прежнему открывают файл через исходную ссылку <code>/file/...</code>.</p><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><ol><li>Откройте настройки загрузки.</li><li>Нажмите Add Channel.</li><li>Выберите <code>WebDAV</code>.</li><li>Введите понятное имя канала, например <code>koofr</code>.</li><li>Введите WebDAV endpoint, например <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Введите username и password.</li><li>По умолчанию оставьте authentication mode как <code>Basic</code>.</li><li>Оставьте storage directory как <code>imgbed</code> или измените на свою директорию.</li><li>Нажмите Save.</li><li>После сохранения проверьте карточку канала, по возможности запросите емкость и загрузите тестовый файл.</li></ol><h2 id="как-проверить" tabindex="-1">Как проверить <a class="header-anchor" href="#как-проверить" aria-label="Permalink to &quot;Как проверить&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Проверка</th><th>Как проверить</th></tr></thead><tbody><tr><td>Карточка канала появилась</td><td>После сохранения на странице настроек загрузки должна появиться карточка WebDAV-канала.</td></tr><tr><td>Канал включен</td><td>Переключатель в правом верхнем углу карточки должен оставаться включенным.</td></tr><tr><td>Учетные данные сохранены</td><td>В деталях должны отображаться Endpoint, username, authentication mode и storage directory.</td></tr><tr><td>Небольшой файл загружается</td><td>Загрузите тестовое изображение и убедитесь, что файл появился в WebDAV-директории.</td></tr><tr><td>Правило для больших файлов работает</td><td>Файлы больше 64 MiB используют chunked upload и создают удаленную директорию чанков.</td></tr><tr><td>Запрос емкости работает</td><td>Если сервер поддерживает информацию об емкости, запрос покажет использованный и общий объем.</td></tr></tbody></table><p><img src="'+o+`" alt="Успешный запрос квоты" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="почему-большие-webdav-фаилы-создают-директорию-чанков" tabindex="-1">Почему большие WebDAV-файлы создают директорию чанков? <a class="header-anchor" href="#почему-большие-webdav-фаилы-создают-директорию-чанков" aria-label="Permalink to &quot;Почему большие WebDAV-файлы создают директорию чанков?&quot;">​</a></h3><p>Это текущий способ хранения больших файлов.</p><p>Файлы больше 64 MiB не склеиваются в один большой удаленный файл. Они хранятся как директория чанков. ImgBed записывает manifest чанков и возвращает полный контент, читая части по порядку.</p><h3 id="что-проверить-в-первую-очередь-если-большая-загрузка-не-работает" tabindex="-1">Что проверить в первую очередь, если большая загрузка не работает? <a class="header-anchor" href="#что-проверить-в-первую-очередь-если-большая-загрузка-не-работает" aria-label="Permalink to &quot;Что проверить в первую очередь, если большая загрузка не работает?&quot;">​</a></h3><p>Сначала проверьте Endpoint, username, password и storage directory. Затем убедитесь, что WebDAV-сервис разрешает создание директорий, запись файлов и чтение файлов.</p><p>Если запрос емкости не работает, но небольшой файл загружается, сервер может просто не поддерживать или ограничивать отчет об емкости. Это не обязательно означает, что загрузка недоступна.</p><h3 id="какои-authentication-mode-выбрать" tabindex="-1">Какой authentication mode выбрать? <a class="header-anchor" href="#какои-authentication-mode-выбрать" aria-label="Permalink to &quot;Какой authentication mode выбрать?&quot;">​</a></h3><p>Начните с <code>Basic</code>.</p><p>Если сервер прямо требует digest authentication, используйте <code>Digest</code>.</p><p>Если не уверены, используйте автоматическое согласование.</p><h2 id="короткии-чек-лист" tabindex="-1">Короткий чек-лист <a class="header-anchor" href="#короткии-чек-лист" aria-label="Permalink to &quot;Короткий чек-лист&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Подготовить WebDAV endpoint, username и password</span></span>
<span class="line"><span>-&gt; Открыть настройки загрузки</span></span>
<span class="line"><span>-&gt; Добавить канал</span></span>
<span class="line"><span>-&gt; Выбрать WebDAV</span></span>
<span class="line"><span>-&gt; Ввести Endpoint / username / password</span></span>
<span class="line"><span>-&gt; По умолчанию оставить authentication mode как Basic</span></span>
<span class="line"><span>-&gt; По умолчанию оставить storage directory как imgbed</span></span>
<span class="line"><span>-&gt; Сохранить</span></span>
<span class="line"><span>-&gt; Запросить емкость</span></span>
<span class="line"><span>-&gt; Загрузить тестовый файл</span></span></code></pre></div>`,45)])])}const D=i(l,[["render",p]]);export{f as __pageData,D as default};
